// Log Provider Usage for Cost Tracking
const panel = $input.first().json;
const provider = panel.currentProvider || 'gemini';
const imageIndex = panel.imageIndex;
const bookId = panel.bookId;
const isCover = panel.isCover || false;

// Detailed logging for cost tracking and debugging
console.log('═══════════════════════════════════════════');
console.log(`📊 PROVIDER USAGE LOG`);
console.log(`├─ Provider: ${provider.toUpperCase()}`);
console.log(`├─ Book ID: ${bookId}`);
console.log(`├─ Type: ${isCover ? '🖼️ Cover' : '📖 Page Image ' + (imageIndex + 1)}`);
console.log(`├─ Timestamp: ${new Date().toISOString()}`);
console.log('═══════════════════════════════════════════');

// Pass through all data including binary for upload
return [{
  json: panel,
  binary: $input.first().binary
}];

const panel = $('Loop Images2').first().json;
const setup = $('Setup2').first().json;
const charDesc = panel.characterDescription || '';
const sceneDesc = panel.imagePrompt || 'illustration';
const style = panel.config.imageStyle || 'watercolor';

// Reference image support
const hasRefImage = panel.hasReferenceImage || setup.hasReferenceImage || false;
const refImageMode = panel.referenceImageMode || setup.referenceImageMode || 'style';
const refImageBase64 = panel.referenceImageBase64 || setup.referenceImageBase64 || null;

// Build prompt: Characters + Scene + Style
let finalPrompt = '';

if (charDesc) {
  finalPrompt = charDesc + '. Scene: ' + sceneDesc;
} else {
  finalPrompt = sceneDesc;
}

// Handle reference image based on mode
if (hasRefImage) {
  if (refImageMode === 'style') {
    // Style Copy mode: Create new images inspired by the reference style
    console.log('🎨 Reference Image Mode: STYLE COPY');
    finalPrompt += `, rendered in the exact same visual style as a provided reference artwork, carefully matching its color palette, brushwork texture, line quality, lighting mood, and artistic technique. ${style} style inspired, children book illustration, consistent character design, high quality, cohesive visual identity`;
  } else if (refImageMode === 'edit') {
    // Direct Edit mode: Note that this requires the Edit API endpoint
    // For now, we add a note - full implementation requires switching to /v1/images/edits
    console.log('🎨 Reference Image Mode: DIRECT EDIT');
    console.log('⚠️ Note: Direct Edit mode requires the OpenAI Images Edit API endpoint');
    finalPrompt += `, ${style} style, children book illustration, consistent character design, high quality, vibrant colors`;
  }
} else {
  finalPrompt += `, ${style} style, children book illustration, consistent character design, high quality, vibrant colors`;
}

// Keep prompt concise (token limit)
if (finalPrompt.length > 1500) {
  finalPrompt = finalPrompt.substring(0, 1500);
}

console.log('🎨 Generating image', panel.imageIndex + 1, 'of', panel.totalImages);
console.log('📸 Has Reference Image:', hasRefImage);
console.log('📸 Reference Mode:', refImageMode);
console.log('📝 Final Prompt:', finalPrompt.substring(0, 200) + '...');

return [{
  json: {
    ...panel,
    finalPrompt: finalPrompt,
    hasReferenceImage: hasRefImage,
    referenceImageMode: refImageMode,
    referenceImageBase64: refImageBase64
  }
}];

const data = $('Parse Outline2').first().json;
const setup = $('Setup2').first().json;
const allPanels = [];
let imageIndex = 0;

console.log('📋 Setup data keys:', Object.keys(data).join(', '));
console.log('🔑 Supabase URL present:', !!data.supabaseUrl);
console.log('🌍 Language:', setup.language);
console.log('📸 Has Reference Image:', setup.hasReferenceImage);
console.log('📸 Reference Mode:', setup.referenceImageMode || 'none');

for (const page of data.outline.pages) {
  for (const panel of page.panels) {
    allPanels.push({
      imageIndex: imageIndex++,
      pageNumber: page.number,
      pageIndex: page.number - 1,
      panelIndex: panel.panelIndex,
      imagePrompt: panel.imagePrompt,
      pageText: page.text,
      characterDescription: data.characterDescription || '',
      jobId: data.jobId,
      bookId: data.bookId,
      userId: data.userId,
      callbackUrl: data.callbackUrl,
      webhookSecret: data.webhookSecret,
      config: data.config,
      totalImages: data.totalImages,
      totalPages: data.outline.pages.length,
      supabaseUrl: data.supabaseUrl,
      supabaseServiceKey: data.supabaseServiceKey,
      storageBucket: data.storageBucket,
      language: setup.language,
      languageName: setup.languageName,
      messages: setup.messages,
      // Reference image data for style transfer or editing
      hasReferenceImage: setup.hasReferenceImage || false,
      referenceImageBase64: setup.referenceImageBase64 || null,
      referenceImageMode: setup.referenceImageMode || null
    });
  }
}

console.log('🎨 Prepared', allPanels.length, 'images for generation');

return allPanels.map(p => ({ json: p }));

const response = $input.first().json;
const setup = $('Setup2').first().json;

let outline;
let characterDescription = '';

try {
  let outlineText = '';

  // Parse OpenAI response structure
  if (response.choices?.[0]?.message?.content) {
    outlineText = response.choices[0].message.content;
  } else if (response.text) {
    outlineText = response.text;
  } else if (typeof response === 'string') {
    outlineText = response;
  }

  // Clean up potential markdown code blocks
  outlineText = outlineText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  outline = JSON.parse(outlineText);
  characterDescription = outline.characterDescription || '';

  console.log('✅ GPT-4o Outline parsed successfully');
  console.log('📝 Character Description:', characterDescription.substring(0, 200) + '...');
  console.log('📖 Pages:', outline.pages.length);
} catch (e) {
  console.error('❌ Failed to parse GPT-4o response:', e);

  // Fallback structure
  const fallbackCharacters = setup.config.mainCharacters || 'a character';
  characterDescription = `Character: ${fallbackCharacters} in ${setup.config.imageStyle || 'illustration'} style`;

  outline = {
    bookSummary: setup.config.title,
    characterDescription: characterDescription,
    pages: Array.from({ length: setup.totalPages }, (_, i) => ({
      number: i + 1,
      text: `Text für Seite ${i + 1}`,
      panels: [{ panelIndex: 0, imagePrompt: 'scene illustration' }]
    }))
  };
}

// Validate and normalize structure
if (!outline.pages || outline.pages.length === 0) {
  outline.pages = Array.from({ length: setup.totalPages }, (_, i) => ({
    number: i + 1,
    text: `Seite ${i + 1}`,
    panels: [{ panelIndex: 0, imagePrompt: 'scene' }]
  }));
}

// Normalize pages
outline.pages = outline.pages.map((page, i) => {
  const panels = Array.isArray(page.panels) ? page.panels : [{ panelIndex: 0, imagePrompt: 'scene' }];
  return {
    number: i + 1,
    text: page.text || `Seite ${i + 1}`,
    panels: panels.map((p, j) => ({
      panelIndex: j,
      imagePrompt: p.imagePrompt || p.description || 'scene'
    }))
  };
});

// Calculate total images
const totalImages = outline.pages.reduce((sum, p) => sum + p.panels.length, 0);

console.log('📊 Total images to generate:', totalImages);

return [{
  json: {
    ...setup,
    outline: outline,
    characterDescription: characterDescription,
    totalImages: totalImages
  }
}];

