    storagePath: storagePath,
    imageUrl: imageUrl,
    currentProvider: 'gpt-image-1.5',
    supabaseUrl: panel.supabaseUrl || setup.supabaseUrl,
    supabaseServiceKey: panel.supabaseServiceKey || setup.supabaseServiceKey,
    storageBucket: panel.storageBucket || setup.storageBucket,
