}];

// Prepare Cover Generation Request
// This runs FIRST before page images for immediate visual feedback
const data = $input.first().json;
const setup = $('Setup2').first().json;

const config = data.config || setup.config;
const title = config.title || 'Untitled Book';
const genre = config.genre || 'Children\'s book';
const description = config.description || '';
const characterDescription = data.characterDescription || config.mainCharacters || '';
const visualStyle = config.imageStyle || 'illustration';

// Build the cover generation prompt
const coverPrompt = `Create a ${visualStyle} artwork for a book titled "${title}".

CRITICAL REQUIREMENTS:
- Generate ONLY the front cover artwork as a FLAT, 2D image
- NO 3D book rendering, NO book spine, NO book edges
- The entire image should be filled with the cover artwork edge-to-edge

CHARACTER CONSISTENCY (use these exact descriptions):
${characterDescription}

Genre: ${genre}
Description: ${description}

Include the book title "${title}" in elegant, readable typography that fits the ${visualStyle} style.`;

console.log('📕 Preparing cover generation...');
console.log('📝 Cover Prompt:', coverPrompt.substring(0, 300) + '...');

// Create storage path for cover
const userId = data.userId || setup.userId || 'anonymous';
const bookId = data.bookId || setup.bookId;
const storagePath = `${userId}/${bookId}/cover.png`;

return [{
  json: {
    ...data,
    coverPrompt: coverPrompt,
    coverStoragePath: storagePath,
    isCover: true,
    supabaseUrl: data.supabaseUrl || setup.supabaseUrl,
    supabaseServiceKey: data.supabaseServiceKey || setup.supabaseServiceKey,
    storageBucket: data.storageBucket || setup.storageBucket
  }
}];

// Parse Cover Image Response
const response = $input.first().json;
const prepData = $('Prepare Cover Request').first().json;
const setup = $('Setup2').first().json;

let imageBase64 = '';
let tempImageUrl = '';

try {
  // OpenAI returns either b64_json or url
  if (response.data?.[0]?.b64_json) {
    imageBase64 = response.data[0].b64_json;
    console.log('✅ Got Base64 cover image from OpenAI');
  } else if (response.data?.[0]?.url) {
    tempImageUrl = response.data[0].url;
    console.log('✅ Got URL cover image from OpenAI:', tempImageUrl.substring(0, 50) + '...');
  } else {
    console.error('❌ No cover image data in response');
    // Continue without cover - don't block the workflow
    return [{ json: { ...prepData, coverSkipped: true, skipReason: 'No image data in response' } }];
  }
} catch (error) {
  console.error('❌ Failed to parse cover response:', error);
  return [{ json: { ...prepData, coverSkipped: true, skipReason: error.message } }];
}

// Create final public URL
const coverUrl = `${prepData.supabaseUrl}/storage/v1/object/public/${prepData.storageBucket}/${prepData.coverStoragePath}`;

console.log('📕 Cover Storage Path:', prepData.coverStoragePath);
console.log('🔗 Cover URL:', coverUrl);

// Prepare binary data for upload
let binaryData = {};
if (imageBase64) {
  binaryData = {
    data: {
      data: imageBase64,
      mimeType: 'image/png',
      fileName: 'cover.png'
    }
  };
}

return [{
  json: {
    ...prepData,
    coverUrl: coverUrl,
    coverImageBase64: imageBase64,
    coverTempUrl: tempImageUrl,
    isCover: true,
    currentProvider: 'gpt-image-1.5'
  },
  binary: binaryData
}];

// Continue to page image generation after cover is done
const prepData = $('Prepare Cover Request').first().json;

console.log('📕 Cover generation complete, continuing to page images...');

return [{ json: prepData }];

// Skip cover generation - error occurred
const prepData = $('Prepare Cover Request').first().json;

console.warn('⚠️ Cover generation failed, continuing without cover...');

return [{ json: { ...prepData, coverSkipped: true } }];

// Convert base64 reference image to binary for multipart upload
const panel = $input.first().json;

const refImageBase64 = panel.referenceImageBase64;
if (!refImageBase64) {
  throw new Error('No reference image base64 data found');
}

// Clean base64 (remove data URI prefix if present)
let cleanBase64 = refImageBase64;
if (cleanBase64.startsWith('data:')) {
  cleanBase64 = cleanBase64.split(',')[1];
}

// Convert to binary buffer
const binaryData = Buffer.from(cleanBase64, 'base64');

// Return with binary data attached
return [{
  json: {
    ...panel
  },
  binary: {
    referenceImage: {
      data: binaryData.toString('base64'),
      mimeType: 'image/png',
      fileName: 'reference.png',
      fileSize: binaryData.length,
      fileExtension: 'png'
    }
  }
}];

// Parse Edit API Image response - same format as generations
const panel = $('Loop Images2').first().json;
const setup = $('Setup2').first().json;
const response = $input.first().json;

const storagePath = `${panel.userId || setup.userId || 'anonymous'}/${panel.bookId || setup.bookId}/page-${panel.pageIndex}-panel-${panel.panelIndex}.png`;
