}

console.log('✅ Parse Edit API Image:', panel.imageIndex + 1, '/', panel.totalImages);
console.log('📁 Storage Path:', storagePath);
console.log('🎨 Used Reference Image: YES (Edit API)');
console.log('📊 Base64 length:', imageBase64.length);

