if (imageBase64) {
  binaryData = {
    data: {
      data: imageBase64,
      mimeType: 'image/png',
      fileName: `page-${panel.pageIndex}-panel-${panel.panelIndex}.png`
    }
  };
}

return [{
  json: {
    ...panel,
    storagePath: storagePath,
    imageUrl: imageUrl,
    currentProvider: 'gpt-image-1.5-edit',
    supabaseUrl: panel.supabaseUrl || setup.supabaseUrl,
